let blogListContainer, blogPostContainer, blogLandingContainer;

function initBlog() {
    blogListContainer = document.getElementById('blog-list');
    blogPostContainer = document.getElementById('blog-post');
    blogLandingContainer = document.getElementById('blog-landing');

    if (blogListContainer) {
        renderBlogList();
    }
}

function renderBlogList() {
    console.log('renderBlogList called');
    console.log('blogListContainer:', blogListContainer);

    if (!blogListContainer) {
        console.error('blogListContainer not found!');
        return;
    }

    blogListContainer.innerHTML = '';
    blogPosts.forEach(post => {
        const card = document.createElement('div');
        card.className = 'blog-card';
        card.innerHTML = `
            <h3>${post.title}</h3>
            <div class="meta">${post.imageDescription}</div>
            <div class="summary">${post.summary}</div>
        `;
        card.addEventListener('click', () => {
            console.log('Card clicked:', post.id);
            showBlogPost(post.id);
        });
        blogListContainer.appendChild(card);
    });
    console.log('Rendered', blogPosts.length, 'blog cards');
}

function showBlogPost(id) {
    const post = blogPosts.find(p => p.id === id);
    if (!post) return;

    // Use defined image path
    const imagePath = post.image;

    // Check if the image exists (this is tricky in client-side JS without causing 404 console errors, 
    // so we'll rely on the onerror event of the img tag)
    const imageHtml = `
        <div class="blog-post-image">
            <img src="${imagePath}" alt="${post.title}" onerror="this.parentElement.style.display='none'">
        </div>`;

    // Render Post Content
    blogPostContainer.innerHTML = `
        <div class="blog-post-container">
            <button class="back-button">← Back to Articles</button>
            <div class="blog-post-header">
                ${imageHtml}
                <h2>${post.title}</h2>
                <div class="meta">Image description: ${post.imageDescription}</div>
            </div>
            <div class="blog-post-content">
                ${post.content}
            </div>
        </div>
    `;

    // Re-attach event listener to the new back button
    const backBtn = blogPostContainer.querySelector('.back-button');
    if (backBtn) {
        backBtn.addEventListener('click', showBlogList);
    }

    if (blogLandingContainer) {
        blogLandingContainer.classList.add('hidden');
    } else {
        blogListContainer.classList.add('hidden'); // Fallback
    }

    blogPostContainer.classList.remove('hidden');

    window.scrollTo(0, 0);
}

function showBlogList() {
    blogPostContainer.classList.add('hidden');
    if (blogLandingContainer) {
        blogLandingContainer.classList.remove('hidden');
    } else {
        blogListContainer.classList.remove('hidden'); // Fallback
    }
}

// Initialize when the DOM is loaded
document.addEventListener('DOMContentLoaded', () => {
    initBlog();
});
